mapper.select:
SELECT * FROM kb_document

    is_delete = 0

        AND (
            visible_dept_ids IS NULL
            OR visible_dept_ids LIKE CONCAT('%', #{deptId}, '%')
            OR dept_id = #{deptId}
            OR dept_id IN (
                SELECT dept_id FROM sys_dept WHERE ancestors LIKE CONCAT('%', #{deptId}, '%')
                OR dept_id = #{deptId}
            )
        )


        AND (category_id = #{categoryId} OR category_id IN
        (SELECT category_id FROM kb_category WHERE parent_id = #{categoryId}
        OR category_id = #{categoryId}))


ORDER BY create_time DESC
